import 'package:flutter/material.dart';import 'package:provider/provider.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_list_item.dart';import '../../models/budget.dart';import '../../models/transaction.dart';import '../../providers/insights_provider.dart';import '../../services/mock_data_service.dart';import 'create_edit_budget_screen.dart';import 'transaction_detail_screen.dart';class BudgetDetailScreen extends StatelessWidget {  final Budget budget;  const BudgetDetailScreen({super.key, required this.budget});  @override  Widget build(BuildContext context) {    final progress = budget.progress.clamp(0.0, 1.0);    final isOverBudget = budget.isOverBudget;    final progressBarColor = isOverBudget ? AppColors.error : AppColors.primary;    final transactionsInBudget = MockDataService.transactions        .where((t) =>            budget.categories.contains(t.category) &&            t.date.isAfter(budget.startDate.subtract(const Duration(days: 1))) &&            (budget.endDate == null ||                t.date.isBefore(budget.endDate!.add(const Duration(days: 1)))))        .toList();    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text(budget.name, style: AppTypography.h2),        actions: [          DsIconButton(            icon: Icons.edit_outlined,            onPressed: () {              Navigator.of(context).push(MaterialPageRoute(                builder: (_) => CreateEditBudgetScreen(budget: budget),              ));            },          ),          SizedBox(width: AppSpacing.paddingSmall),        ],      ),      body: ListView(        padding: AppSpacing.screenPadding,        children: [          DsCard(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text('Budget Target',                    style: AppTypography.body.copyWith(color: AppColors.textSecondary)),                SizedBox(height: AppSpacing.paddingSmall),                Text(                  MockDataService.formatCurrency(budget.totalAmount),                  style: AppTypography.h1,                ),                SizedBox(height: AppSpacing.paddingMedium),                Text('Spent',                    style: AppTypography.body.copyWith(color: AppColors.textSecondary)),                SizedBox(height: AppSpacing.paddingSmall),                Text(                  MockDataService.formatCurrency(budget.spentAmount),                  style: AppTypography.h1.copyWith(                    color: isOverBudget ? AppColors.error : AppColors.textPrimary,                  ),                ),                SizedBox(height: AppSpacing.paddingMedium),                LinearProgressIndicator(                  value: progress,                  backgroundColor: AppColors.surface.withOpacity(0.5),                  valueColor: AlwaysStoppedAnimation<Color>(progressBarColor),                  borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                  minHeight: 10,                ),                SizedBox(height: AppSpacing.paddingSmall),                Row(                  mainAxisAlignment: MainAxisAlignment.spaceBetween,                  children: [                    Text(                      '${(progress * 100).toStringAsFixed(1)}% spent',                      style: AppTypography.caption,                    ),                    Text(                      '${MockDataService.formatCurrency(budget.remainingAmount)} remaining',                      style: AppTypography.caption.copyWith(                        color: isOverBudget ? AppColors.error : AppColors.textSecondary,                      ),                    ),                  ],                ),                if (isOverBudget) ...[                  SizedBox(height: AppSpacing.paddingSmall),                  Text(                    'You have exceeded your budget by ${MockDataService.formatCurrency(budget.spentAmount - budget.totalAmount)}.',                    style: AppTypography.body.copyWith(color: AppColors.error),                  ),                ] else if (progress >= budget.alertThreshold) ...[                  SizedBox(height: AppSpacing.paddingSmall),                  Text(                    'You are projected to exceed your budget.',                    style: AppTypography.body.copyWith(color: AppColors.secondary),                  ),                ],              ],            ),          ),          SizedBox(height: AppSpacing.paddingLarge),          Text('Transactions in this Budget', style: AppTypography.h2),          SizedBox(height: AppSpacing.paddingMedium),          if (transactionsInBudget.isEmpty)            DsCard(              child: Text(                'No transactions found for this budget yet.',                style: AppTypography.body.copyWith(color: AppColors.textSecondary),              ),            )          else            DsCard(              padding: EdgeInsets.zero,              child: Column(                children: transactionsInBudget.map((transaction) {                  final isNegative = transaction.amount < 0;                  return DsListItem(                    leading: Container(                      width: AppSpacing.categoryIconSize,                      height: AppSpacing.categoryIconSize,                      decoration: BoxDecoration(                        color: transaction.category.color.withOpacity(0.2),                        borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                      ),                      child: Icon(transaction.category.icon,                          color: transaction.category.color),                    ),                    title: transaction.merchant,                    subtitle:                      '${transaction.category.name} • ${transaction.date.day}/${transaction.date.month}/${transaction.date.year}',                    trailingText: MockDataService.formatCurrency(transaction.amount),                    trailingTextColor: isNegative ? AppColors.error : AppColors.success,                    onTap: () {                      Navigator.of(context).push(MaterialPageRoute(                        builder: (_) => TransactionDetailScreen(transaction: transaction),                      ));                    },                  );                }).toList(),              ),            ),          SizedBox(height: AppSpacing.paddingLarge),          DsSecondaryButton(            text: 'Pause Budget',            onPressed: () {              ScaffoldMessenger.of(context).showSnackBar(                const SnackBar(content: Text('Budget paused (feature coming soon)!')),              );            },          ),          SizedBox(height: AppSpacing.paddingSmall),          DsSecondaryButton(            text: 'Delete Budget',            onPressed: () {              _showDeleteConfirmationDialog(context, budget);            },          ),        ],      ),    );  }  void _showDeleteConfirmationDialog(BuildContext context, Budget budget) {    showDialog(      context: context,      builder: (BuildContext dialogContext) {        return AlertDialog(          backgroundColor: AppColors.surface,          title: Text('Delete Budget', style: AppTypography.h2),          content: Text(            'Are you sure you want to delete the budget "${budget.name}"? This action cannot be undone.',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),          actions: <Widget>[            TextButton(              child: Text('Cancel',                  style: AppTypography.buttonSecondary.copyWith(color: AppColors.textSecondary)),              onPressed: () {                Navigator.of(dialogContext).pop();              },            ),            TextButton(              child: Text('Delete',                  style: AppTypography.buttonSecondary.copyWith(color: AppColors.error)),              onPressed: () {                Provider.of<InsightsProvider>(context, listen: false)                    .deleteBudget(budget.id);                Navigator.of(dialogContext).pop(); // Close dialog                Navigator.of(context).pop(); // Pop from BudgetDetailScreen              },            ),          ],        );      },    );  }}